<?php require_once __DIR__.'/../../config/database.php'; require_once __DIR__.'/../../includes/functions.php'; require_admin(); if($_SERVER['REQUEST_METHOD']==='POST'){ verify_csrf(); if(isset($_POST['delete']))$pdo->prepare('DELETE FROM variables WHERE id=?')->execute([$_POST['id']]); else $pdo->prepare($_POST['id']?'UPDATE variables SET code=?,name=?,description=? WHERE id=?':'INSERT INTO variables(code,name,description) VALUES(?,?,?)')->execute($_POST['id']?[$_POST['code'],$_POST['name'],$_POST['description'],$_POST['id']]:[$_POST['code'],$_POST['name'],$_POST['description']]); } $rows=$pdo->query('SELECT * FROM variables ORDER BY id')->fetchAll(); require_once __DIR__.'/../../includes/header.php'; ?><div class="container-fluid px-3 px-lg-4"><div class="row g-3"><?php include __DIR__.'/../../includes/admin_sidebar.php'; ?><section class="col-lg-9 col-xl-10"><h2 class="section-title mb-3">Master Variabel</h2><form class="card p-3 mb-3" method="post"><?=csrf_field()?><input type="hidden" name="id"><div class="row g-2"><div class="col"><input name="code" class="form-control" placeholder="Kode" required></div><div class="col"><input name="name" class="form-control" placeholder="Nama" required></div><div class="col"><input name="description" class="form-control" placeholder="Deskripsi"></div><div class="col"><button class="btn btn-primary">Simpan</button></div></div></form><div class="table-wrap"><table class="table table-hover"><tr><th>Kode</th><th>Nama</th><th>Deskripsi</th><th>Aksi</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['code'])?></td><td><?=e($r['name'])?></td><td><?=e($r['description'])?></td><td><form method="post"><?=csrf_field()?><input type="hidden" name="id" value="<?=$r['id']?>"><button name="delete" class="btn btn-sm btn-danger">Hapus</button></form></td></tr><?php endforeach; ?></table></div></section></div></div><?php require_once __DIR__.'/../../includes/footer.php'; ?>
